(function(){
  try {
    var all = document.querySelectorAll('*');
    var result = [];
    for (var i = 0; i < all.length; i++) {
      var t = all[i].textContent.trim();
      if (t && (t.indexOf('技能树') >= 0 || t.indexOf('村民') >= 0 || t.indexOf('事件日志') >= 0 || t.indexOf('角色属性') >= 0)) {
        result.push({tag: all[i].tagName, text: t, clickable: all[i].onclick !== null || all[i].getAttribute('onclick') !== null});
      }
    }
    return JSON.stringify(result);
  } catch(e) {
    return JSON.stringify({error: e.message});
  }
})()
